// Parse notification type and prepare message
const body = $input.first().json;
const notificationType = body.type || 'welcome';

const templates = {
  welcome: {
    template: 'billed_welcome',
    message: `Namaste {{1}}! 🎉

Aapki shop "{{2}}" Billed par live hai!

🌐 URL: {{3}}
📧 Email: {{4}}

Start billing now!`,
    params: ['ownerName', 'shopName', 'siteUrl', 'email']
  },
  credentials: {
    template: 'billed_credentials',
    message: `🔐 Billed Login Credentials

🌐 URL: {{1}}
📧 Email: {{2}}
🔑 Password: {{3}}

Please change password after login.`,
    params: ['siteUrl', 'email', 'password']
  },
  dailySummary: {
    template: 'billed_daily_summary',
    message: `📊 Daily Sales Summary - {{1}}

💰 Total Sales: ₹{{2}}
📄 Invoices: {{3}}
🏆 Top Item: {{4}}

View detailed reports: {{1}}`,
    params: ['shopName', 'totalSales', 'invoiceCount', 'topItem']
  },
  lowStock: {
    template: 'billed_low_stock',
    message: `⚠️ Low Stock Alert - {{1}}

📦 Item: {{2}}
📊 Current Stock: {{3}}
🔔 Reorder Level: {{4}}

Reorder now to avoid stockouts!`,
    params: ['shopName', 'itemName', 'currentStock', 'reorderLevel']
  },
  planExpiry: {
    template: 'billed_plan_expiry',
    message: `⏰ Plan Expiry Reminder - {{1}}

📋 Your {{2}} plan expires on {{3}}

Renew now to continue uninterrupted service.

Visit: billed.in/renew`,
    params: ['shopName', 'planName', 'expiryDate']
  }
};

const template = templates[notificationType] || templates.welcome;

// Format phone number
const rawPhone = body.phone || '';
const phone = rawPhone.startsWith('91') ? rawPhone : '91' + rawPhone.replace(/\D/g, '');

return {
  json: {
    ...body,
    notificationType,
    phone,
    templateName: template.template,
    templateParams: [
      body.ownerName || body.params?.[0] || '',
      body.shopName || body.params?.[1] || '',
      body.siteUrl || body.params?.[2] || '',
      body.email || body.params?.[3] || ''
    ],
    message: template.message.replace(
      /\{\{(\d+)\}\}/g,
      (_, idx) => body[template.params[parseInt(idx) - 1]] || body.params?.[parseInt(idx) - 1] || ''
    )
  }
};

// Format phone for Twilio
const body = $input.first().json;
const phone = body.phone.startsWith('91') ? body.phone : '91' + body.phone.replace(/\D/g, '');

return {
  json: {
    ...body,
    twilioPhone: '+' + phone
  }
};
